            aOrbiterC = (aOrbiterC + aOrbiterE) + 0x67726D5CE6B24A90ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterC) ^ 0x2531B7364A10E329ULL;
            aOrbiterF = RotL64((aOrbiterF * 0x3CE94E9C4C116D85ULL), 13U);
            //
            aOrbiterD = ((aOrbiterD + aOrbiterK) + 0x9BB76D67534305E8ULL) + aPhaseEOrbiterUpdateSaltD[((aIndex + 28U)) & S_SALT1];
