            aCarry = aCarry + (RotL64(aWandererG, 51U) ^ aWandererE);
            aCarry = aCarry + (aWandererK ^ RotL64(aWandererA, 24U));
            aCarry = aCarry + (RotL64(aWandererD, 35U) ^ aWandererB);
