            //
            aOrbiterF = (aWandererB + RotL64(aIngress, 58U)) + 0xC4C7C1C2F9A50DC6ULL;
            aOrbiterG = ((aWandererA + RotL64(aPrevious, 47U)) + 0x1DA3358C823336BDULL) + aPhaseCOrbiterAssignSaltF[(((31U - aIndex) + 27U)) & S_SALT1];
            aOrbiterB = (aWandererF + RotL64(aCross, 13U)) + 0x50DE3F8A24C44BC2ULL;
            aOrbiterI = ((aWandererC + RotL64(aScatter, 43U)) + RotL64(aCarry, 57U)) + 0x01E9A18C991AE847ULL;
            aOrbiterJ = ((aWandererJ + RotL64(aCross, 53U)) + RotL64(aCarry, 3U)) + 0xB9C6FBD2A51AB7E8ULL;
            aOrbiterD = (aWandererE + RotL64(aScatter, 36U)) + 0xBE5F14C38AB9E81DULL;
            aOrbiterK = ((aWandererG + RotL64(aPrevious, 29U)) + 0xAAFA4702678314D0ULL) + aPhaseCOrbiterAssignSaltD[(((31U - aIndex) + 7U)) & S_SALT1];
            aOrbiterA = ((aWandererH + RotL64(aIngress, 5U)) + RotL64(aCarry, 29U)) + 0x587D13238939F43CULL;
            aOrbiterH = (aWandererD + RotL64(aScatter, 23U)) + 0x30884E7AEC9443B4ULL;
            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 0xD7351DD80817DEA7ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterF) ^ 0x8965534E474F1A17ULL;
