            aOrbiterD = (aOrbiterD + aOrbiterK) + 0x12A86D42F4414D15ULL;
            aOrbiterF = ((aOrbiterF ^ aOrbiterD) ^ 0x43419EBF89E46F79ULL) ^ aPhaseCOrbiterUpdateSaltC[((aIndex + 15U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 0x2C6733E9A0977D55ULL), 57U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterD) + 0x0381F94614DB5A59ULL) + aPhaseCOrbiterUpdateSaltF[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterA) ^ 0xD3420BB2F5B8965DULL;
            aOrbiterI = RotL64((aOrbiterI * 0x2CE1AFB7311DA46BULL), 29U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterJ) + 0x93251EE24E0F764DULL) + aPhaseCOrbiterUpdateSaltD[(((31U - aIndex) + 14U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterH) ^ 0xB13176D92F97AEF6ULL;
            aOrbiterA = RotL64((aOrbiterA * 0xF1F91F21D062EA7DULL), 23U);
