            aOrbiterK = RotL64((aOrbiterK * 0x5B9CFC50C6FAF423ULL), 11U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterA) + 0xBE8AAA769C37DE22ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterK) ^ 0x38576583B4843EEAULL;
            aOrbiterG = RotL64((aOrbiterG * 0x466BEA993B53B921ULL), 39U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterB) + 0xE57DA6F206F50855ULL;
            aOrbiterD = ((aOrbiterD ^ aOrbiterJ) ^ 0x77F2DCABE6AC7429ULL) ^ aPhaseCOrbiterUpdateSaltE[((aIndex + 19U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0xE254F56DECB769C3ULL), 19U);
