            aOrbiterH = (aOrbiterH ^ aOrbiterG) ^ 0x09C39F70D2C9C4E5ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x3720E5CD18717B89ULL), 3U);
            //
            aIngress = RotL64(aOrbiterD, 3U) ^ aOrbiterA;
            aIngress = aIngress + (aOrbiterI ^ RotL64(aOrbiterF, 6U));
            aIngress = aIngress + (aOrbiterK ^ RotL64(aOrbiterH, 47U));
