            aWandererF = aWandererF ^ ((RotL64(aScatter, 43U) + RotL64(aOrbiterK, 19U)) + aOrbiterG);
            aWandererD = aWandererD + (((RotL64(aIngress, 18U) + RotL64(aOrbiterK, 24U)) + aOrbiterH) + aPhaseBWandererUpdateSaltC[(((31U - aIndex) + 11U)) & S_SALT1]);
            aWandererJ = aWandererJ ^ ((RotL64(aCross, 29U) + RotL64(aOrbiterK, 37U)) + aOrbiterI);
            //
            aCarry = aCarry + (RotL64(aWandererH, 60U) ^ aWandererI);
