            aOrbiterD = RotL64((aOrbiterD * 0x8734E045DD2CECE3ULL), 27U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterD) + 0x90C6755592E041B3ULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterK) ^ 0x23659E58E6AC0448ULL;
            aOrbiterC = RotL64((aOrbiterC * 0xCCC75E30D92D5815ULL), 3U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterG) + 0x3CB5D1ACFD045D76ULL) + aPhaseGOrbiterUpdateSaltF[((aIndex + 18U)) & S_SALT1];
            aOrbiterB = ((aOrbiterB ^ aOrbiterH) ^ 0x8C7B9C73AF54537AULL) ^ aPhaseGOrbiterUpdateSaltC[(((31U - aIndex) + 27U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 0x76832EFCA7B49A33ULL), 51U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterB) + 0xC0B3C457C0F1F3A1ULL;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterD) ^ 0x47DB618D46DB5977ULL) ^ aPhaseGOrbiterUpdateSaltA[(((31U - aIndex) + 15U)) & S_SALT1];
            aOrbiterJ = RotL64((aOrbiterJ * 0x910D67C3C156F5CFULL), 47U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterI) + 0x9146AB8EB4450C3CULL;
