            //
            aWandererE = aWandererE + (((RotL64(aIngress, 19U) + RotL64(aOrbiterK, 11U)) + aOrbiterD) + aPhaseGWandererUpdateSaltF[(((31U - aIndex) + 3U)) & S_SALT1]);
