            aPrevious = aIngress;
            //
            aIngress = (RotL64(aOperationLaneB[((aIndex + 7027U)) & S_BLOCK1], 54U) ^ RotL64(aWorkLaneC[((aIndex + 9546U)) & S_BLOCK1], 37U));
            aIngress ^= (RotL64(aScrapLaneA[((aIndex + 9075U)) & S_BLOCK1], 21U) ^ RotL64(aInvestLaneE[((S_BLOCK1 - aIndex + 7057U)) & S_BLOCK1], 11U));
            aIngress = TwistMix64::DiffuseC(aIngress);
            //
            aCross = (RotL64(aWorkLaneA[((S_BLOCK1 - aIndex + 10038U)) & S_BLOCK1], 41U) ^ RotL64(aWorkLaneD[((S_BLOCK1 - aIndex + 9485U)) & S_BLOCK1], 50U));
            aCross ^= RotL64(aInvestLaneA[((aIndex + 7662U)) & S_BLOCK1], 21U);
            aCross = TwistMix64::DiffuseB(aCross);
            //
            aScatter = (RotL64(aCarry, 27U) + RotL64(aIngress, 11U)) ^ (RotL64(aPrevious, 56U) + RotL64(aCross, 39U));
            aScatter = TwistMix64::DiffuseA(aScatter);
