            aOrbiterC = ((aWandererB + RotL64(aCross, 41U)) + RotL64(aCarry, 23U)) + 0x58E573A5F2FED8F6ULL;
            aOrbiterB = (aWandererI + RotL64(aPrevious, 47U)) + 0xB0BC5A1ADC7C46E6ULL;
