            aOrbiterF = ((aWandererH + RotL64(aIngress, 56U)) + 0xC306FDCA07616B64ULL) + aPhaseGOrbiterAssignSaltE[(((31U - aIndex) + 19U)) & S_SALT1];
            aOrbiterJ = (aWandererG + RotL64(aCross, 19U)) + 0x0A1D0B0B0C7BB428ULL;
            aOrbiterG = ((aWandererC + RotL64(aScatter, 53U)) + 0xFEA34B744726AF20ULL) + aPhaseGOrbiterAssignSaltC[((aIndex + 10U)) & S_SALT1];
            aOrbiterI = (aWandererJ + RotL64(aPrevious, 13U)) + 0x4BD525DEB8F31389ULL;
            aOrbiterK = ((aWandererD + RotL64(aIngress, 37U)) + RotL64(aCarry, 51U)) + 0x2CACA82D04265503ULL;
            aOrbiterE = (aWandererF + RotL64(aCross, 21U)) + 0x4F9F56105B2E4104ULL;
            aOrbiterH = ((aWandererE + RotL64(aPrevious, 44U)) + RotL64(aCarry, 3U)) + 0xBBD78AF101CAD236ULL;
            aOrbiterD = (aWandererA + RotL64(aScatter, 27U)) + 0xDD1C20EF5F0B0BD8ULL;
