            aOrbiterC = (aOrbiterC + aOrbiterB) + 0xAFB09BA2FCC5D833ULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterC) ^ 0xC694874B1064ADB4ULL) ^ aPhaseGOrbiterUpdateSaltC[((aIndex + 13U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0xBBF6F0F9EDEA8F43ULL), 35U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterJ) + 0xE37D8F7973D69B85ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterF) ^ 0x36187583C9E8916FULL;
