            //
            aOrbiterG = (aOrbiterG + aOrbiterA) + 0x24B7D4494B825587ULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterG) ^ 0x86AF271366277853ULL) ^ aPhaseGOrbiterUpdateSaltE[((aIndex + 21U)) & S_SALT1];
            aOrbiterI = RotL64((aOrbiterI * 0x0A8AF5F350BAA6BDULL), 11U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterK) + 0x2245086127085AD6ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterA) ^ 0xD693D4148A7EEAD0ULL;
            aOrbiterF = RotL64((aOrbiterF * 0xB5C76D7055D6461FULL), 57U);
